python3 -c "
import sys, json, subprocess, os, re
from collections import Counter
try:
    data = json.load(sys.stdin)
    path = data.get('tool_input', {}).get('file_path', '')
    if '/server/pneuma/core/' not in path and '/server/pneuma/memory/' not in path: sys.exit(0)
    root = re.sub(r'/server/.*', '', path)
    dirs = [f'{root}/server/pneuma/core', f'{root}/server/pneuma/memory']
    lines = []
    for d in dirs:
        if os.path.isdir(d):
            r = subprocess.run(['grep', '-rn', '--include=*.js', '-E', r'^export (async )?function \w+', d], capture_output=True, text=True)
            lines.extend(l for l in r.stdout.strip().splitlines() if l)
    if not lines: sys.exit(0)
    names = [m.group(1) for l in lines for m in [re.search(r'function (\w+)', l)] if m]
    dupes = [n for n, c in Counter(names).items() if c > 1]
    if not dupes: sys.exit(0)
    sigs = chr(10).join(lines)
    prompt = f'Exported function names duplicated across server/pneuma/core/ or server/pneuma/memory/: {chr(44).join(dupes)}\n\nSignatures:\n{sigs}\n\nAre these logic duplicates or same-name-different-purpose? List file:function pairs only. No tools needed, analyze only what I provided.'
    r2 = subprocess.run(['claude', '-p', prompt, '--model', 'claude-haiku-4-5-20251001'], capture_output=True, text=True, timeout=60)
    out = (r2.stdout or r2.stderr or '').strip()
    if out: print('[DupeGuard]', out)
except SystemExit as e: sys.exit(e.code)
except Exception as e: print('[DupeGuard error]', e)
"

python3 -c "
import sys, json, subprocess, re
try:
    data = json.load(sys.stdin)
    path = data.get('tool_input', {}).get('file_path', '')
    if not path.endswith(('.js', '.jsx', '.ts', '.tsx')): sys.exit(0)
    for segment in ('client', 'server'):
        m = re.search(r'(.*/' + segment + r')/', path)
        if m:
            root = m.group(1)
            rel = path[len(root)+1:]
            r = subprocess.run(['npx', 'eslint', '--fix', '--max-warnings=0', rel], capture_output=True, text=True, cwd=root, timeout=30)
            out = (r.stdout + r.stderr).strip()
            if r.returncode != 0 and out:
                print(f'[ESLint/{segment}]', out[:600])
            break
except SystemExit as e: sys.exit(e.code)
except Exception as e: print('[ESLint hook error]', e)
"
